// @vitest-environment node
/**
 * SPEC-022: nota y export de una entrevista grabada en modo degradado — la
 * generación funciona con líneas speaker null y el export etiqueta cada
 * intervención con las etiquetas genéricas existentes ("Tú"/"Interlocutor 1").
 * Generated by QA Dev agent.
 *
 * Arnés de SPEC-017: SDK y dialog mockeados, store/repository y transcript
 * REALES (el archivo lleva TODAS las líneas con speaker null, como las
 * persiste una sesión degradada).
 */
import { mkdtempSync, readFileSync, writeFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import { exportInterviewDocument, generateInterviewNote } from '../../../src/main/noteService'

const harness = vi.hoisted(() => {
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    showSaveDialog: vi.fn(),
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  dialog: {
    showSaveDialog: harness.showSaveDialog
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  }
}))

function sdkResponse(payload: Record<string, unknown>): unknown {
  return {
    stop_reason: 'end_turn',
    content: [
      { type: 'thinking', thinking: 'razonamiento' },
      { type: 'text', text: JSON.stringify(payload) }
    ]
  }
}

/** Transcript de una sesión degradada: TODAS las líneas con speaker null. */
function writeDegradedTranscript(): string {
  const dir = mkdtempSync(join(tmpdir(), 'maurya-degraded-note-'))
  const transcriptPath = join(dir, 'degradada.transcript.json')
  writeFileSync(
    transcriptPath,
    JSON.stringify({
      lines: [
        {
          channel: 'mic',
          speaker: null,
          text: '¿Cómo gestionáis hoy el registro?',
          startMs: 0,
          endMs: 1000,
          receivedAtMs: 1100
        },
        {
          channel: 'system',
          speaker: null,
          text: 'Todo a mano, nos lleva dos días.',
          startMs: 1000,
          endMs: 2000,
          receivedAtMs: 2100
        }
      ],
      latency: null,
      assistant: null,
      consent: null
    })
  )
  return transcriptPath
}

let dataDir = ''

beforeEach(() => {
  vi.clearAllMocks()
  dataDir = mkdtempSync(join(tmpdir(), 'maurya-degraded-notes-'))
  initStore(dataDir)
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test'
})

afterEach(() => {
  delete process.env['ANTHROPIC_API_KEY']
})

describe('noteService (degradación SPEC-022)', () => {
  // SPEC-022 · AC-10
  it('generates the note from a degraded recording and exports the transcript with the generic speaker labels', async () => {
    const discovery = repository.createDiscovery({ name: 'Vertical Sanidad' })
    const template = repository.createNoteTemplate({
      name: 'Notas discovery',
      sections: [{ title: 'Dolores', description: 'Problemas detectados' }]
    })
    const interview = repository.createInterview({
      discoveryId: discovery.id,
      title: 'Captura degradada'
    })
    repository.updateInterview(interview.id, {
      transcriptPath: writeDegradedTranscript(),
      status: 'recorded'
    })
    harness.create.mockResolvedValue(
      sdkResponse({
        sections: [{ title: 'Dolores', contentMarkdown: 'Registro manual detectado.' }]
      })
    )

    // La generación funciona con normalidad sobre líneas sin hablante...
    const result = await generateInterviewNote(interview.id, template.id)
    expect(result.interview.status).toBe('summarized')
    expect(result.note.contentMarkdown).toBe('## Dolores\n\nRegistro manual detectado.')
    // ...y el prompt etiqueta cada intervención con las etiquetas genéricas
    // (speaker null → mic "Tú", system "Interlocutor 1", sin huecos)
    const params = harness.create.mock.calls[0][0] as { messages: Array<{ content: string }> }
    expect(params.messages[0].content).toContain('[Tú] ¿Cómo gestionáis hoy el registro?')
    expect(params.messages[0].content).toContain('[Interlocutor 1] Todo a mano')

    // El export usa las mismas etiquetas genéricas, una línea por intervención
    const outDir = mkdtempSync(join(tmpdir(), 'maurya-degraded-export-'))
    const outPath = join(outDir, 'transcripcion.md')
    harness.showSaveDialog.mockResolvedValueOnce({ canceled: false, filePath: outPath })
    const outcome = await exportInterviewDocument(null, interview.id, 'transcript')
    expect(outcome.saved).toBe(true)
    expect(readFileSync(outPath, 'utf-8')).toBe(
      '**Tú:** ¿Cómo gestionáis hoy el registro?\n**Interlocutor 1:** Todo a mano, nos lleva dos días.'
    )
  })
})
